CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), phone VARCHAR(20) UNIQUE NOT NULL, username VARCHAR(30) UNIQUE, bio TEXT, avatar_url TEXT, is_creator BOOLEAN NOT NULL DEFAULT false, is_active BOOLEAN NOT NULL DEFAULT true, wallet_balance INTEGER NOT NULL DEFAULT 0, became_creator_at TIMESTAMPTZ, last_login TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS otp_codes (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), phone VARCHAR(20) NOT NULL, code VARCHAR(6) NOT NULL, used BOOLEAN NOT NULL DEFAULT false, expires_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS videos (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), creator_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, title VARCHAR(150) NOT NULL, description TEXT, video_url TEXT NOT NULL, storage_path TEXT NOT NULL, thumbnail_url TEXT, tags TEXT[] DEFAULT '{}', status VARCHAR(20) NOT NULL DEFAULT 'published' CHECK (status IN ('published','processing','deleted','banned')), views INTEGER NOT NULL DEFAULT 0, likes_count INTEGER NOT NULL DEFAULT 0, comments_count INTEGER NOT NULL DEFAULT 0, shares_count INTEGER NOT NULL DEFAULT 0, file_size BIGINT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS video_likes (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), video_id UUID NOT NULL REFERENCES videos(id) ON DELETE CASCADE, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(video_id, user_id));
CREATE TABLE IF NOT EXISTS comments (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), video_id UUID NOT NULL REFERENCES videos(id) ON DELETE CASCADE, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, content TEXT NOT NULL CHECK (char_length(content) <= 500), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS conversations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), participant_a_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, participant_b_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(participant_a_id, participant_b_id));
CREATE TABLE IF NOT EXISTS messages (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), conversation_id UUID NOT NULL REFERENCES conversations(id) ON DELETE CASCADE, sender_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, content TEXT CHECK (char_length(content) <= 2000), media_url TEXT, message_type VARCHAR(20) NOT NULL DEFAULT 'text' CHECK (message_type IN ('text','image','video','audio')), read_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS transactions (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, type VARCHAR(20) NOT NULL CHECK (type IN ('deposit','withdrawal','earning','refund','fee')), amount INTEGER NOT NULL, net_amount INTEGER, status VARCHAR(20) NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','processing','completed','failed','cancelled')), description TEXT, cinetpay_transaction_id VARCHAR(50), metadata JSONB DEFAULT '{}', confirmed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS follows (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), follower_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, following_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(follower_id, following_id));
CREATE OR REPLACE FUNCTION increment_views(video_id UUID) RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$ BEGIN UPDATE videos SET views = views + 1 WHERE id = video_id AND status = 'published'; END; $$;
CREATE OR REPLACE FUNCTION increment_wallet_balance(user_id UUID, amount INTEGER) RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$ BEGIN IF amount <= 0 THEN RAISE EXCEPTION 'Montant positif requis'; END IF; UPDATE users SET wallet_balance = wallet_balance + amount WHERE id = user_id; END; $$;
CREATE OR REPLACE FUNCTION decrement_wallet_balance(user_id UUID, amount INTEGER) RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$ DECLARE b INTEGER; BEGIN IF amount <= 0 THEN RAISE EXCEPTION 'Montant positif requis'; END IF; SELECT wallet_balance INTO b FROM users WHERE id = user_id FOR UPDATE; IF b < amount THEN RAISE EXCEPTION 'Solde insuffisant: % FCFA', b; END IF; UPDATE users SET wallet_balance = wallet_balance - amount WHERE id = user_id; END; $$;
ALTER TABLE users ENABLE ROW LEVEL SECURITY;
ALTER TABLE otp_codes ENABLE ROW LEVEL SECURITY;
ALTER TABLE videos ENABLE ROW LEVEL SECURITY;
ALTER TABLE video_likes ENABLE ROW LEVEL SECURITY;
ALTER TABLE comments ENABLE ROW LEVEL SECURITY;
ALTER TABLE conversations ENABLE ROW LEVEL SECURITY;
ALTER TABLE messages ENABLE ROW LEVEL SECURITY;
ALTER TABLE transactions ENABLE ROW LEVEL SECURITY;
ALTER TABLE follows ENABLE ROW LEVEL SECURITY;
CREATE POLICY "videos_public" ON videos FOR SELECT USING (status = 'published');
CREATE POLICY "comments_public" ON comments FOR SELECT USING (true);
